using Microsoft.EntityFrameworkCore;

class CosmosDbContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();

    protected override void OnConfiguring(DbContextOptionsBuilder optionsBuilder)
    {
        optionsBuilder.UseCosmos(
            "https://localhost:8081",
            "C2y6yDjf5/R+ob0N8A7Cgv30VRDJIWEHLM+4QDU5DE2nQ9nDuVTqobD4b8mGGyPMbIZnqyMsEcaGQy67XIw/Jw==",
            "EfAppDb");
    }

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // Breaking change: EF Core 9 Cosmos provider renamed the discriminator property
        // from "Discriminator" to "$type". Existing documents still use "Discriminator",
        // so we must explicitly configure the old property name to avoid data loss.
        modelBuilder.Entity<Product>(b =>
        {
            b.ToContainer("Products");
            b.HasDiscriminator<string>("Discriminator");
        });
    }
}

class Product
{
    public string Id { get; set; } = default!;
    public string Name { get; set; } = default!;
}

using Microsoft.EntityFrameworkCore;

class CosmosQueryService
{
    // Breaking change: EF Core 9 Cosmos provider removed synchronous query support.
    // All queries must use async methods (ToListAsync, FirstOrDefaultAsync, etc.).
    async Task<List<Product>> GetProductsAsync(CosmosDbContext db)
    {
        return await db.Products.ToListAsync();
    }

    async Task<Product?> FindProductAsync(CosmosDbContext db, string name)
    {
        return await db.Products.FirstOrDefaultAsync(p => p.Name == name);
    }
}

