{
    // Breaking change: EF Core 9 Cosmos provider removed synchronous query support.
    // All queries must use async methods (ToListAsync, FirstOrDefaultAsync, etc.).
    async Task<List<Product>> GetProductsAsync(CosmosDbContext db)
    {
        return await db.Products.ToListAsync();
    }

    async Task<Product?> FindProductAsync(CosmosDbContext db, string name)
    {
        return await db.Products.FirstOrDefaultAsync(p => p.Name == name);
    }
}

